const body = $json.body || $json || {};

const formId = String(body.form_id || '');
const formName = body.form_name || null;
const dateFrom = body.date_from;
const dateTo = body.date_to;

if (!formId || !dateFrom || !dateTo) {
  throw new Error('form_id, date_from, and date_to are required');
}

const zendeskQuery = `type:ticket ticket_form_id:${formId} created>=${dateFrom} created<${dateTo} custom_field_1260824167549:support_`;

return [{
  json: {
    form_id: formId,
    form_name: formName,
    date_from: dateFrom,
    date_to: dateTo,
    zendesk_query: zendeskQuery
  }
}];

// Receives output from HTTP - Count Full Range (one item with { count: N })
// Also reads webhook body via node reference for form/date context
const prepData = $('Code - Prep Count Query').first().json;
const totalCount = Number($json.count || 0);

const formId = prepData.form_id;
const formName = prepData.form_name || null;
const dateFrom = prepData.date_from;
const dateTo = prepData.date_to;

// 5-day windows using >= start / < end so no gaps at boundaries.
// At ~170 tickets/day, 5 days = ~850 tickets per chunk — safely under the 1,000-result Zendesk cap.
const CHUNK_DAYS = 5;

const runId = `ticket-sync-${formId}-${dateFrom.replace(/-/g, '')}-${Date.now()}`;

const chunks = [];
let cursor = new Date(dateFrom + 'T00:00:00Z');
const rangeEnd = new Date(dateTo + 'T00:00:00Z');

while (cursor < rangeEnd) {
  const chunkFrom = cursor.toISOString().slice(0, 10);
  const nextCursor = new Date(cursor);
  nextCursor.setUTCDate(nextCursor.getUTCDate() + CHUNK_DAYS);
  if (nextCursor > rangeEnd) nextCursor.setTime(rangeEnd.getTime());
  const chunkTo = nextCursor.toISOString().slice(0, 10);

  chunks.push({
    run_id: runId,
    form_id: formId,
    form_name: formName,
    date_from: chunkFrom,
    date_to: chunkTo,
    total_count_estimate: totalCount
  });

  cursor = nextCursor;
}

const totalChunks = chunks.length;

return chunks.map((c, i) => ({
  json: {
    ...c,
    chunk_num: i + 1,
    total_chunks: totalChunks
  }
}));
